// GET /api/posts?limit=20&after=<cursor>

/**
 * Encode a compound cursor into an opaque base64 string.
 * The cursor captures the sort key of the LAST row on the current page:
 * (created_at, id). This is what the next page filters against.
 */
function encodeCursor(row) {
    const payload = JSON.stringify({
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

/**
 * Decode an opaque cursor back into its components.
 * Throws on any malformed input so the caller can return a 400.
 */
function decodeCursor(cursor) {
    let parsed;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        parsed = JSON.parse(json);
    } catch (err) {
        throw new Error('INVALID_CURSOR');
    }

    // Validate shape: both fields must be present and well-formed.
    if (
        parsed == null ||
        typeof parsed !== 'object' ||
        typeof parsed.created_at !== 'string' ||
        !(typeof parsed.id === 'number' || typeof parsed.id === 'string')
    ) {
        throw new Error('INVALID_CURSOR');
    }

    const createdAt = new Date(parsed.created_at);
    if (isNaN(createdAt.getTime())) {
        throw new Error('INVALID_CURSOR');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.max(1, Math.min(limit, 100));

    const params = [];
    let whereCursor = '';

    // Only apply the cursor filter when `after` is provided (page 2+).
    if (req.query.after !== undefined && req.query.after !== '') {
        let cursor;
        try {
            cursor = decodeCursor(req.query.after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid cursor' });
        }

        // Compound (created_at, id) comparison matching ORDER BY created_at DESC, id DESC.
        // Row-value comparison gives us the correct "strictly after" semantics:
        //   (created_at, id) < (cursor.created_at, cursor.id)
        // This is index-friendly with an index on (created_at DESC, id DESC).
        params.push(cursor.created_at, cursor.id);
        whereCursor = `AND (created_at, id) < ($${params.length - 1}, $${params.length})`;
    }

    // LIMIT N+1 trick: fetch one extra row to detect whether more pages exist.
    params.push(limit + 1);
    const limitParamIndex = params.length;

    const result = await db.query(
        `SELECT id, title, content, author_id, created_at
         FROM posts
         WHERE published = true
         ${whereCursor}
         ORDER BY created_at DESC, id DESC
         LIMIT $${limitParamIndex}`,
        params
    );

    const rows = result.rows;
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor =
        hasMore && posts.length > 0
            ? encodeCursor(posts[posts.length - 1])
            : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Key implementation notes

- **No OFFSET.** Paging happens through the `WHERE (created_at, id) < ($n, $n+1)` row-value comparison. PostgreSQL evaluates this as a true tuple comparison, which exactly matches `ORDER BY created_at DESC, id DESC` and correctly handles rows sharing the same `created_at`.
- **Index recommendation.** For this to be fast, have an index that matches the sort: `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;` (a partial index on `published = true` keeps it tight). The row-value comparison can then seek directly to the cursor position.
- **N+1 trick.** We request `limit + 1`. If that many come back, `hasMore = true` and we trim to `limit`; `nextCursor` is built from the last *returned* row.
- **Opaque cursor.** Base64url-encoded JSON of `{created_at, id}`. Clients treat it as a black box, which lets you change the internal structure later without breaking them. I used `base64url` to keep cursors URL-safe (no `+`, `/`, or `=` needing escaping in query strings).
- **Graceful failure.** `decodeCursor` throws `INVALID_CURSOR` on bad base64, bad JSON, or wrong shape; the handler maps that to a `400`.
- **No COUNT.** Removed entirely.

## Why cursor-based is superior here

1. **Performance at scale.** `OFFSET 1000000` forces PostgreSQL to scan and discard a million rows on every request—cost grows linearly with how deep you page. A cursor's `WHERE (created_at, id) < (...)` is an index seek: roughly constant time regardless of page depth.
2. **Stable results under writes.** With offsets, a row inserted or deleted while a user pages shifts every subsequent row, causing **skipped or duplicated** items across pages. A cursor anchors to a fixed sort position, so concurrent inserts/deletes don't corrupt the stream—ideal for a feed ordered by `created_at DESC`.
3. **Dropping COUNT.** `SELECT COUNT(*)` on a large table is an expensive scan run on every request. Cursor pagination doesn't need a total to function (`hasMore` answers "is there a next page?"), so you shed that cost.

The trade-off: you lose random access to an arbitrary page number (no "jump to page 47") and total-count display. For an infinite-scroll / "load more" feed like posts, that's exactly the access pattern you want anyway.

